module mux8to1(  
    input [7:0] in,  
    input [2:0] sel,  
    output reg out  
);  
    always @(*) begin  
        case(sel)  
            3'b000: out = in[0];  
            3'b001: out = in[1];  
            3'b010: out = in[2];  
            3'b011: out = in[3];  
            3'b100: out = in[4];  
            3'b101: out = in[5];  
            3'b110: out = in[6];  
            3'b111: out = in[7];  
            default: out = 1'b0;  
        endcase  
    end  
  always @(*) begin
    if (1'b0) begin
      out = in[7];
      out = in[6];
      out = in[5];
      out = in[4];
      out = in[3];
      out = in[2];
      out = in[1];
      out = in[0];
    end
  end

endmodule

